public int longestPalindromeSubseq(String word1, String word2) {
    int n = word1.length();
    int m = word2.length();

    int[][] dp = new int[1001][1001];

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (word1.charAt(i) == word2.charAt(j)) {
                dp[i + 1][j + 1] = dp[i][j] + 1;
            } else {
                dp[i + 1][j + 1] = Math.max(dp[i][j + 1], dp[i + 1][j]);
            }
        }
    }

    return dp[n][m];
}
